const express = require('express');
const crypto = require('crypto');
const app = express();

// Stripe webhook secret (store in Azure Key Vault)
const WEBHOOK_SECRET = process.env.STRIPE_WEBHOOK_SECRET; // e.g., whsec_abc123...

// CRITICAL: Use raw body for signature verification
app.use('/webhooks/stripe', express.raw({ type: 'application/json' }));

// Stripe webhook signature verification
function verifyStripeSignature(req) {
  const signature = req.headers['stripe-signature'];

  if (!signature) {
    throw new Error('Missing Stripe signature header');
  }

  // Parse signature header: t=timestamp,v1=signature
  const elements = signature.split(',');
  const sigMap = {};

  for (const element of elements) {
    const [key, value] = element.split('=');
    sigMap[key] = value;
  }

  const timestamp = sigMap.t;
  const v1Signature = sigMap.v1;

  if (!timestamp || !v1Signature) {
    throw new Error('Invalid signature format');
  }

  // Verify timestamp is within 5 minutes (300 seconds) to prevent replay
  const currentTime = Math.floor(Date.now() / 1000);
  const timeDifference = currentTime - parseInt(timestamp);

  if (timeDifference > 300) {
    throw new Error(`Webhook timestamp too old: ${timeDifference}s (max 300s)`);
  }

  // Construct signed payload: timestamp.raw_body
  const signedPayload = `${timestamp}.${req.body.toString()}`;

  // Compute expected signature using HMAC-SHA256
  const expectedSignature = crypto
    .createHmac('sha256', WEBHOOK_SECRET)
    .update(signedPayload)
    .digest('hex');

  // Constant-time comparison to prevent timing attacks
  const isValid = crypto.timingSafeEqual(
    Buffer.from(v1Signature),
    Buffer.from(expectedSignature)
  );

  if (!isValid) {
    throw new Error('Invalid webhook signature');
  }

  return true;
}

// Idempotency tracking to prevent duplicate processing
const processedEvents = new Set(); // Use Redis in production

app.post('/webhooks/stripe', async (req, res) => {
  try {
    // Step 1: Verify signature and timestamp
    verifyStripeSignature(req);

    // Step 2: Parse event
    const event = JSON.parse(req.body.toString());

    // Step 3: Check idempotency (prevent duplicate processing)
    if (processedEvents.has(event.id)) {
      console.log(`Event ${event.id} already processed (replay detected)`);
      return res.status(200).json({ received: true, status: 'duplicate' });
    }

    // Step 4: Process event
    switch (event.type) {
      case 'payment_intent.succeeded':
        const paymentIntent = event.data.object;
        await processPayment(paymentIntent);
        break;

      case 'charge.refunded':
        const refund = event.data.object;
        await processRefund(refund);
        break;

      default:
        console.log(`Unhandled event type: ${event.type}`);
    }

    // Step 5: Mark event as processed
    processedEvents.add(event.id);
    // In production: await redis.setex(`webhook:${event.id}`, 86400, 'processed');

    // Step 6: Return success immediately (Stripe expects 2xx within 5 seconds)
    res.status(200).json({ received: true });

  } catch (error) {
    console.error('Webhook verification failed:', error.message);
    res.status(400).json({ error: error.message });
  }
});

