const app = express();

const GITHUB_WEBHOOK_SECRET = process.env.GITHUB_WEBHOOK_SECRET;

app.use('/webhooks/github', express.json());

function verifyGitHubSignature(req) {
  const signature256 = req.headers['x-hub-signature-256'];
  const signature = req.headers['x-hub-signature']; // Legacy SHA-1

  // Require SHA-256 (SHA-1 is deprecated due to collision attacks)
  if (!signature256) {
    throw new Error('Missing X-Hub-Signature-256 header');
  }

  // Compute expected signature
  const payload = JSON.stringify(req.body);
  const expectedSignature = 'sha256=' + crypto
    .createHmac('sha256', GITHUB_WEBHOOK_SECRET)
    .update(payload)
    .digest('hex');

  // Constant-time comparison (prevent timing attacks)
  if (signature256.length !== expectedSignature.length) {
    throw new Error('Invalid signature length');
  }

  const isValid = crypto.timingSafeEqual(
    Buffer.from(signature256),
    Buffer.from(expectedSignature)
  );

  if (!isValid) {
    throw new Error('Invalid GitHub webhook signature');
  }

  return true;
}

const processedDeliveries = new Set();

app.post('/webhooks/github', async (req, res) => {
  try {
    // Verify signature
    verifyGitHubSignature(req);

    // Extract GitHub delivery ID (for idempotency)
    const deliveryId = req.headers['x-github-delivery'];
    const event = req.headers['x-github-event'];

    if (!deliveryId) {
      return res.status(400).json({ error: 'Missing X-GitHub-Delivery header' });
    }

    // Check for replay
    if (processedDeliveries.has(deliveryId)) {
      console.log(`Delivery ${deliveryId} already processed (replay detected)`);
      return res.status(200).json({ received: true, status: 'duplicate' });
    }

    // Process event
    console.log(`Processing GitHub event: ${event}`);

    switch (event) {
      case 'push':
        await handlePushEvent(req.body);
