package com.example.webhooks;

import org.springframework.web.bind.annotation.*;
import org.springframework.http.ResponseEntity;
import org.springframework.beans.factory.annotation.Value;
import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.security.MessageDigest;
import java.time.Instant;
import java.util.concurrent.TimeUnit;
import org.springframework.data.redis.core.RedisTemplate;

@RestController
@RequestMapping("/webhooks")
public class StripeWebhookController {

    @Value("${stripe.webhook.secret}")
    private String webhookSecret;

    private final RedisTemplate<String, String> redisTemplate;

    public StripeWebhookController(RedisTemplate<String, String> redisTemplate) {
        this.redisTemplate = redisTemplate;
    }

    @PostMapping("/stripe")
    public ResponseEntity<?> handleStripeWebhook(
            @RequestHeader("Stripe-Signature") String stripeSignature,
            @RequestBody String payload) {

        try {
            // Parse signature header
            String[] elements = stripeSignature.split(",");
            Long timestamp = null;
            String v1Signature = null;

            for (String element : elements) {
                String[] keyValue = element.split("=");
                if ("t".equals(keyValue[0])) {
                    timestamp = Long.parseLong(keyValue[1]);
                } else if ("v1".equals(keyValue[0])) {
                    v1Signature = keyValue[1];
                }
            }

            if (timestamp == null || v1Signature == null) {
                return ResponseEntity.badRequest().body("Invalid signature format");
            }

            // Verify timestamp (prevent replay attacks)
            long currentTime = Instant.now().getEpochSecond();
            if (currentTime - timestamp > 300) { // 5 minutes
                return ResponseEntity.status(400)
                    .body("Webhook timestamp too old: " + (currentTime - timestamp) + "s");
            }

            // Compute expected signature
            String signedPayload = timestamp + "." + payload;
            String expectedSignature = computeHmacSha256(signedPayload, webhookSecret);

            // Constant-time comparison
            if (!MessageDigest.isEqual(
                    v1Signature.getBytes(),
                    expectedSignature.getBytes())) {
                return ResponseEntity.status(401).body("Invalid webhook signature");
            }

            // Parse event
            com.google.gson.JsonObject event = 
                new com.google.gson.JsonParser().parse(payload).getAsJsonObject();
            String eventId = event.get("id").getAsString();
            String eventType = event.get("type").getAsString();

            // Idempotency check with Redis
            String redisKey = "webhook:stripe:" + eventId;
            Boolean isNew = redisTemplate.opsForValue().setIfAbsent(
                redisKey, "processed", 24, TimeUnit.HOURS);

            if (Boolean.FALSE.equals(isNew)) {
                return ResponseEntity.ok().body(
                    Map.of("received", true, "status", "duplicate"));
            }

            // Process event
            switch (eventType) {
                case "payment_intent.succeeded":
                    processPaymentSuccess(event);
                    break;
                case "charge.refunded":
                    processRefund(event);
                    break;
                default:
                    System.out.println("Unhandled event type: " + eventType);
            }

            return ResponseEntity.ok().body(Map.of("received", true));

        } catch (Exception e) {
            return ResponseEntity.status(400).body("Webhook processing failed: " + e.getMessage());
        }
    }

    private String computeHmacSha256(String data, String secret) throws Exception {
        Mac hmac = Mac.getInstance("HmacSHA256");
        SecretKeySpec secretKey = new SecretKeySpec(secret.getBytes(), "HmacSHA256");
        hmac.init(secretKey);
        byte[] hash = hmac.doFinal(data.getBytes());

        // Convert to hex
        StringBuilder hexString = new StringBuilder();
        for (byte b : hash) {
            String hex = Integer.toHexString(0xff & b);
            if (hex.length() == 1) hexString.append('0');
            hexString.append(hex);
        }
        return hexString.toString();
    }

    private void processPaymentSuccess(com.google.gson.JsonObject event) {
        System.out.println("Processing payment success: " + event.get("id"));
        // Credit user account
    }

    private void processRefund(com.google.gson.JsonObject event) {
        System.out.println("Processing refund: " + event.get("id"));
        // Handle refund logic
    }
}

