    host=os.environ.get('REDIS_HOST', 'localhost'),
    port=6379,
    decode_responses=True
)

WEBHOOK_SECRET = os.environ.get('STRIPE_WEBHOOK_SECRET')
TIMESTAMP_TOLERANCE = 300  # 5 minutes

def verify_stripe_signature(payload, signature_header):
    """Verify Stripe webhook signature with timestamp validation."""

    if not signature_header:
        raise ValueError('Missing Stripe-Signature header')

    # Parse signature header
    sig_elements = {}
    for element in signature_header.split(','):
        key, value = element.split('=')
        sig_elements[key] = value

    timestamp = sig_elements.get('t')
    v1_signature = sig_elements.get('v1')

    if not timestamp or not v1_signature:
        raise ValueError('Invalid signature format')

    # Verify timestamp (prevent replay attacks)
    current_time = int(time.time())
    time_difference = current_time - int(timestamp)

    if time_difference > TIMESTAMP_TOLERANCE:
        logger.warning(
            f'Webhook replay attempt detected',
            extra={
                'custom_dimensions': {
                    'time_difference': time_difference,
                    'timestamp': timestamp,
                    'ip_address': request.remote_addr
                }
            }
        )
        raise ValueError(f'Timestamp too old: {time_difference}s (max {TIMESTAMP_TOLERANCE}s)')

    # Compute expected signature
    signed_payload = f"{timestamp}.{payload}"
    expected_signature = hmac.new(
        WEBHOOK_SECRET.encode('utf-8'),
        signed_payload.encode('utf-8'),
        hashlib.sha256
    ).hexdigest()

    # Constant-time comparison (prevent timing attacks)
    if not hmac.compare_digest(v1_signature, expected_signature):
        logger.error(
            'Invalid webhook signature',
            extra={
                'custom_dimensions': {
                    'ip_address': request.remote_addr,
                    'provided_signature': v1_signature[:8] + '...',  # Truncated for security
                }
            }
        )
        raise ValueError('Invalid webhook signature')

    return True

@app.route('/webhooks/stripe', methods=['POST'])
def stripe_webhook():
    """Handle Stripe webhook events with signature validation."""

    try:
        # Get raw payload (required for signature verification)
        payload = request.get_data(as_text=True)
        signature = request.headers.get('Stripe-Signature')

        # Step 1: Verify signature and timestamp
        verify_stripe_signature(payload, signature)

        # Step 2: Parse event
        import json
        event = json.loads(payload)
        event_id = event['id']
        event_type = event['type']

        # Step 3: Idempotency check
        redis_key = f'webhook:stripe:{event_id}'
        is_new = redis_client.set(redis_key, 'processed', ex=86400, nx=True)

        if not is_new:
            logger.info(
                f'Duplicate webhook event detected',
                extra={
                    'custom_dimensions': {
                        'event_id': event_id,
                        'event_type': event_type,
                        'ip_address': request.remote_addr
                    }
                }
            )
            return jsonify({'received': True, 'status': 'duplicate'}), 200

        # Step 4: Process event
        logger.info(
            f'Processing webhook event',
            extra={
                'custom_dimensions': {
                    'event_id': event_id,
                    'event_type': event_type
                }
            }
        )

        if event_type == 'payment_intent.succeeded':
            payment_intent = event['data']['object']
            process_payment_success(payment_intent)
        elif event_type == 'charge.refunded':
            refund = event['data']['object']
            process_refund(refund)
        else:
            logger.debug(f'Unhandled event type: {event_type}')

        return jsonify({'received': True}), 200

    except ValueError as e:
        logger.error(
            f'Webhook validation failed: {str(e)}',
            extra={'custom_dimensions': {'ip_address': request.remote_addr}}
        )
        return jsonify({'error': str(e)}), 400

    except Exception as e:
        logger.exception('Webhook processing error')
        return jsonify({'error': 'Internal server error'}), 500

